     3→import { useState } from "react";
     4→import { useRouter } from "next/navigation";
     5→import { Button } from "@/components/ui/button";
     6→import { Input } from "@/components/ui/input";
     7→import { Label } from "@/components/ui/label";
     8→import { Switch } from "@/components/ui/switch";
     9→import { Textarea } from "@/components/ui/textarea";
    10→import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
    11→import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
    12→import type { Source, SourceInput } from "@/lib/api/types";
    13→import { validateRepository } from "@/lib/format";
    14→
    15→interface SourceFormProps {
    16→  initial?: Source;
    17→  projectId?: string;
    18→  onSubmit: (input: SourceInput) => Promise<void>;
    19→  title: string;
    20→  redirectTo?: string;
    21→  onSuccess?: () => void;
    22→  onCancel?: () => void;
    23→}
    24→
    25→
    26→export function SourceForm({ initial, onSubmit, title, redirectTo, onSuccess, onCancel }: SourceFormProps) {
    27→  const router = useRouter();
    28→  const [saving, setSaving] = useState(false);
    29→  const [error, setError] = useState("");
    30→  const [provider, setProvider] = useState(initial?.provider ?? "dockerhub");
    31→  const [repository, setRepository] = useState(initial?.repository ?? "");
    32→  const [pollInterval, setPollInterval] = useState(String(initial?.poll_interval_seconds ?? 86400));
    33→  const [enabled, setEnabled] = useState(initial?.enabled ?? true);
    34→  const [configJson, setConfigJson] = useState(
    35→    JSON.stringify(initial?.config ?? {}, null, 2)
    36→  );
    37→  const [versionFilterInclude, setVersionFilterInclude] = useState(initial?.version_filter_include ?? "");
    38→  const [versionFilterExclude, setVersionFilterExclude] = useState(initial?.version_filter_exclude ?? "");
    39→
    40→  const handleSubmit = async (e: React.FormEvent) => {
    41→    e.preventDefault();
    42→    setError("");
    43→
    44→    const repoError = validateRepository(provider, repository);
    45→    if (repoError) {
    46→      setError(repoError);
    47→      return;
    48→    }
    49→
    50→    let parsedConfig: Record<string, unknown> | undefined;
    51→    if (configJson.trim() && configJson.trim() !== "{}") {
    52→      try {
    53→        parsedConfig = JSON.parse(configJson);
    54→      } catch {
    55→        setError("Config must be valid JSON");
    56→        return;
    57→      }
    58→    }
    59→
    60→    setSaving(true);
    61→    try {
    62→      await onSubmit({
    63→        provider,
    64→        repository: repository.trim(),
    65→        poll_interval_seconds: Number(pollInterval),
    66→        enabled,
    67→        config: parsedConfig,
    68→        version_filter_include: versionFilterInclude.trim() || undefined,
    69→        version_filter_exclude: versionFilterExclude.trim() || undefined,
    70→      });
    71→      if (onSuccess) {
    72→        onSuccess();
    73→      } else {
    74→        router.push(redirectTo ?? "/sources");
    75→      }
    76→    } catch (err: unknown) {
    77→      setError(err instanceof Error ? err.message : "Failed to save");
    78→    } finally {
    79→      setSaving(false);
    80→    }
    81→  };
    82→
    83→  const handleCancel = () => {
    84→    if (onCancel) {
    85→      onCancel();
    86→    } else {
    87→      router.back();
    88→    }
    89→  };
    90→
    91→  const formContent = (
    92→    <form onSubmit={handleSubmit} className="space-y-4">
    93→      {error && <div className="rounded-md bg-red-50 p-3 text-sm text-red-700">{error}</div>}
    94→      <div className="space-y-2">
    95→        <Label>Provider</Label>
    96→        <Select value={provider} onValueChange={setProvider}>
    97→          <SelectTrigger><SelectValue /></SelectTrigger>
    98→          <SelectContent>
    99→            <SelectItem value="dockerhub">Docker Hub</SelectItem>
   100→            <SelectItem value="github">GitHub</SelectItem>
   101→          </SelectContent>
   102→        </Select>
   103→      </div>
   104→      <div className="space-y-2">
   105→        <Label htmlFor="repository">Repository</Label>
   106→        <Input id="repository" value={repository} onChange={(e) => setRepository(e.target.value)} placeholder="e.g. library/golang or ethereum/go-ethereum" required />
   107→      </div>
   108→      <div className="space-y-2">
   109→        <Label htmlFor="poll_interval">Poll Interval (seconds)</Label>
   110→        <Input id="poll_interval" type="number" min={60} value={pollInterval} onChange={(e) => setPollInterval(e.target.value)} />
   111→      </div>
   112→      <div className="space-y-2">
   113→        <Label htmlFor="config">Config (JSON, optional)</Label>
   114→        <Textarea
   115→          id="config"
   116→          value={configJson}
   117→          onChange={(e) => setConfigJson(e.target.value)}
   118→          rows={4}
   119→          className="font-mono text-sm"
   120→          placeholder="{}"
   121→        />
   122→      </div>
   123→      <div className="space-y-2">
   124→        <Label htmlFor="version_filter_include">Version Filter — Include (regex, optional)</Label>
   125→        <Input
   126→          id="version_filter_include"
   127→          value={versionFilterInclude}
   128→          onChange={(e) => setVersionFilterInclude(e.target.value)}
   129→          placeholder='e.g. ^v\d+\.\d+\.\d+$'
   130→          className="font-mono text-sm"
   131→        />
   132→        <p className="text-xs text-muted-foreground">Only show/notify versions matching this pattern</p>
   133→      </div>
   134→      <div className="space-y-2">
   135→        <Label htmlFor="version_filter_exclude">Version Filter — Exclude (regex, optional)</Label>
   136→        <Input
   137→          id="version_filter_exclude"
   138→          value={versionFilterExclude}
   139→          onChange={(e) => setVersionFilterExclude(e.target.value)}
   140→          placeholder='e.g. -(alpha|beta|rc|nightly)'
   141→          className="font-mono text-sm"
   142→        />
   143→        <p className="text-xs text-muted-foreground">Hide/suppress versions matching this pattern</p>
   144→      </div>
