   383→              }}
   384→            />
   385→          ) : (
   386→            <p
   387→              style={{
   388→                fontFamily: "var(--font-fraunces)",
   389→                fontStyle: "italic",
   390→                fontSize: "14px",
   391→                color: "#9ca3af",
   392→              }}
   393→            >
   394→              No release notes available
   395→            </p>
   396→          )}
   397→        </div>
   398→      </div>
   399→    </div>
   400→  );
   401→}
   402→
   403→/* ------------------------------------------------------------------ */
   404→/*  Sub-components                                                     */
   405→/* ------------------------------------------------------------------ */
   406→
   407→function DetailRow({
   408→  label,
   409→  value,
   410→  mono,
   411→  small,
   412→}: {
   413→  label: string;
   414→  value: string;
   415→  mono?: boolean;
   416→  small?: boolean;
   417→}) {
   418→  return (
   419→    <div className="flex items-baseline justify-between gap-4">
   420→      <span
   421→        style={{
   422→          fontFamily: "var(--font-dm-sans)",
   423→          fontSize: "13px",
   424→          color: "#9ca3af",
   425→        }}
   426→      >
   427→        {label}
   428→      </span>
   429→      <span
   430→        className="text-right"
   431→        style={{
   432→          fontFamily: mono ? "'JetBrains Mono', monospace" : "var(--font-dm-sans)",
   433→          fontSize: small ? "11px" : "13px",
   434→          color: "#374151",
   435→        }}
   436→      >
   437→        {value}
   438→      </span>
   439→    </div>
   440→  );
   441→}
   442→

