func (s *ECRPublicSource) SourceID() string { return s.sourceID }

func (s *ECRPublicSource) FetchNewReleases(ctx context.Context) ([]IngestionResult, error) {
	token, err := s.fetchToken(ctx)
	if err != nil {
		return nil, fmt.Errorf("ecr-public auth: %w", err)
	}

	url := fmt.Sprintf("%s/v2/%s/tags/list", s.baseURL, s.repository)
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
	if err != nil {
		return nil, fmt.Errorf("create request: %w", err)
	}
	req.Header.Set("Authorization", "Bearer "+token)

	resp, err := s.client.Do(req)
	if err != nil {
		return nil, fmt.Errorf("fetch tags: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("unexpected status: %d", resp.StatusCode)
	}

	var body struct {
		Name string   `json:"name"`
		Tags []string `json:"tags"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&body); err != nil {
		return nil, fmt.Errorf("decode response: %w", err)
	}

	results := make([]IngestionResult, 0, len(body.Tags))
	for _, tag := range body.Tags {
		ts := s.fetchTagCreatedAt(ctx, token, tag)
		results = append(results, IngestionResult{
			Repository: s.repository,
			RawVersion: tag,
			Timestamp:  ts,
		})
	}
	return results, nil
}

