// fetching its manifest to get the config digest, then fetching the config
// blob which contains the "created" field. Falls back to time.Now() on error.
func (s *ECRPublicSource) fetchTagCreatedAt(ctx context.Context, token, tag string) time.Time {
	configDigest, err := s.fetchConfigDigest(ctx, token, tag)
	if err != nil {
		slog.Debug("ecr-public: failed to fetch manifest, using current time",
			"repo", s.repository, "tag", tag, "error", err)
