func (s *ECRPublicSource) fetchConfigDigest(ctx context.Context, token, tag string) (string, error) {
	url := fmt.Sprintf("%s/v2/%s/manifests/%s", s.baseURL, s.repository, tag)
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
	if err != nil {
		return "", err
	}
	req.Header.Set("Authorization", "Bearer "+token)
	req.Header.Set("Accept", "application/vnd.docker.distribution.manifest.v2+json, application/vnd.oci.image.manifest.v1+json")

	resp, err := s.client.Do(req)
	if err != nil {
		return "", err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return "", fmt.Errorf("manifest status %d", resp.StatusCode)
	}

	var manifest struct {
		Config struct {
			Digest string `json:"digest"`
		} `json:"config"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&manifest); err != nil {
		return "", err
	}
	if manifest.Config.Digest == "" {
		return "", fmt.Errorf("empty config digest")
	}
	return manifest.Config.Digest, nil
}

// fetchConfigCreatedAt fetches the config blob and returns the "created" timestamp.
func (s *ECRPublicSource) fetchConfigCreatedAt(ctx context.Context, token, digest string) (time.Time, error) {
	url := fmt.Sprintf("%s/v2/%s/blobs/%s", s.baseURL, s.repository, digest)
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
	if err != nil {
		return time.Time{}, err
	}
	req.Header.Set("Authorization", "Bearer "+token)

	resp, err := s.client.Do(req)
	if err != nil {
		return time.Time{}, err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return time.Time{}, fmt.Errorf("config blob status %d", resp.StatusCode)
	}

	var config struct {
		Created string `json:"created"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&config); err != nil {
		return time.Time{}, err
	}
	if config.Created == "" {
		return time.Time{}, fmt.Errorf("empty created field")
	}

	t, err := time.Parse(time.RFC3339Nano, config.Created)
	if err != nil {
		return time.Time{}, fmt.Errorf("parse created time: %w", err)
	}
	return t, nil
}

func (s *ECRPublicSource) fetchToken(ctx context.Context) (string, error) {
	url := s.baseURL + "/token/"
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
	if err != nil {
		return "", fmt.Errorf("create token request: %w", err)
	}

	resp, err := s.client.Do(req)
	if err != nil {
		return "", fmt.Errorf("fetch token: %w", err)
	}
