package ingestion

import (
	"context"
	"encoding/json"
	"fmt"
	"log/slog"
	"net/http"
	"time"
)

const defaultECRPublicURL = "https://public.ecr.aws"

// ECRPublicSource polls AWS ECR Public Gallery for new image tags
// using the Docker Registry v2 HTTP API.
type ECRPublicSource struct {
	client     *http.Client
	repository string // "registry_alias/repo_name", e.g. "i6b2w2n6/op-node"
	baseURL    string
	sourceID   string
}

func NewECRPublicSource(client *http.Client, repository string, sourceID string) *ECRPublicSource {
	return &ECRPublicSource{
		client:     client,
		repository: repository,
		baseURL:    defaultECRPublicURL,
		sourceID:   sourceID,
	}
}

func (s *ECRPublicSource) Name() string    { return "ecr-public" }
func (s *ECRPublicSource) SourceID() string { return s.sourceID }

func (s *ECRPublicSource) FetchNewReleases(ctx context.Context) ([]IngestionResult, error) {
	token, err := s.fetchToken(ctx)
	if err != nil {
		return nil, fmt.Errorf("ecr-public auth: %w", err)
	}

	url := fmt.Sprintf("%s/v2/%s/tags/list", s.baseURL, s.repository)
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
	if err != nil {
		return nil, fmt.Errorf("create request: %w", err)
	}
	req.Header.Set("Authorization", "Bearer "+token)

	resp, err := s.client.Do(req)
	if err != nil {
		return nil, fmt.Errorf("fetch tags: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("unexpected status: %d", resp.StatusCode)
	}

	var body struct {
		Name string   `json:"name"`
		Tags []string `json:"tags"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&body); err != nil {
		return nil, fmt.Errorf("decode response: %w", err)
	}

	results := make([]IngestionResult, 0, len(body.Tags))
	for _, tag := range body.Tags {
		ts := s.fetchTagCreatedAt(ctx, token, tag)
		results = append(results, IngestionResult{
			Repository: s.repository,
			RawVersion: tag,
			Timestamp:  ts,
		})
	}
	return results, nil
}

// fetchTagCreatedAt retrieves the image creation timestamp for a tag by
// fetching its manifest to get the config digest, then fetching the config
// blob which contains the "created" field. Falls back to time.Now() on error.
func (s *ECRPublicSource) fetchTagCreatedAt(ctx context.Context, token, tag string) time.Time {
	configDigest, err := s.fetchConfigDigest(ctx, token, tag)
	if err != nil {
		slog.Debug("ecr-public: failed to fetch manifest, using current time",
			"repo", s.repository, "tag", tag, "error", err)
		return time.Now()
	}

	created, err := s.fetchConfigCreatedAt(ctx, token, configDigest)
	if err != nil {
		slog.Debug("ecr-public: failed to fetch config blob, using current time",
			"repo", s.repository, "tag", tag, "error", err)
		return time.Now()
	}
	return created
}

// fetchConfigDigest fetches the manifest for a tag and returns the config blob digest.
func (s *ECRPublicSource) fetchConfigDigest(ctx context.Context, token, tag string) (string, error) {
	url := fmt.Sprintf("%s/v2/%s/manifests/%s", s.baseURL, s.repository, tag)
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
	if err != nil {
		return "", err
	}
	req.Header.Set("Authorization", "Bearer "+token)
	req.Header.Set("Accept", "application/vnd.docker.distribution.manifest.v2+json, application/vnd.oci.image.manifest.v1+json")

	resp, err := s.client.Do(req)
	if err != nil {
		return "", err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return "", fmt.Errorf("manifest status %d", resp.StatusCode)
	}

	var manifest struct {
		Config struct {
			Digest string `json:"digest"`
		} `json:"config"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&manifest); err != nil {
		return "", err
	}
	if manifest.Config.Digest == "" {
		return "", fmt.Errorf("empty config digest")
	}
	return manifest.Config.Digest, nil
}

// fetchConfigCreatedAt fetches the config blob and returns the "created" timestamp.
func (s *ECRPublicSource) fetchConfigCreatedAt(ctx context.Context, token, digest string) (time.Time, error) {
	url := fmt.Sprintf("%s/v2/%s/blobs/%s", s.baseURL, s.repository, digest)
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
	if err != nil {
		return time.Time{}, err
	}
	req.Header.Set("Authorization", "Bearer "+token)

	resp, err := s.client.Do(req)
	if err != nil {
		return time.Time{}, err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return time.Time{}, fmt.Errorf("config blob status %d", resp.StatusCode)
	}

	var config struct {
		Created string `json:"created"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&config); err != nil {
		return time.Time{}, err
	}
	if config.Created == "" {
		return time.Time{}, fmt.Errorf("empty created field")
	}

	t, err := time.Parse(time.RFC3339Nano, config.Created)
	if err != nil {
		return time.Time{}, fmt.Errorf("parse created time: %w", err)
	}
	return t, nil
}

func (s *ECRPublicSource) fetchToken(ctx context.Context) (string, error) {
	url := s.baseURL + "/token/"
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
	if err != nil {
		return "", fmt.Errorf("create token request: %w", err)
	}

	resp, err := s.client.Do(req)
	if err != nil {
		return "", fmt.Errorf("fetch token: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return "", fmt.Errorf("token endpoint returned status %d", resp.StatusCode)
	}

	var body struct {
		Token string `json:"token"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&body); err != nil {
		return "", fmt.Errorf("decode token response: %w", err)
	}
	return body.Token, nil
}

