// fetchConfigDigest fetches the manifest for a tag and returns the config blob digest.
// Handles both single manifests and manifest lists (multi-arch images).
func (s *ECRPublicSource) fetchConfigDigest(ctx context.Context, token, ref string) (string, error) {
	url := fmt.Sprintf("%s/v2/%s/manifests/%s", s.baseURL, s.repository, ref)
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
	if err != nil {
		return "", err
	}
	req.Header.Set("Authorization", "Bearer "+token)
	req.Header.Set("Accept", strings.Join([]string{
		"application/vnd.docker.distribution.manifest.v2+json",
		"application/vnd.oci.image.manifest.v1+json",
		"application/vnd.docker.distribution.manifest.list.v2+json",
		"application/vnd.oci.image.index.v1+json",
	}, ", "))

	resp, err := s.client.Do(req)
	if err != nil {
		return "", err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return "", fmt.Errorf("manifest status %d", resp.StatusCode)
	}

	var raw json.RawMessage
	if err := json.NewDecoder(resp.Body).Decode(&raw); err != nil {
		return "", err
	}

	// Probe for manifest list / OCI index (has "manifests" array).
	var index struct {
		Manifests []struct {
			Digest   string `json:"digest"`
			Platform struct {
				Architecture string `json:"architecture"`
				OS           string `json:"os"`
			} `json:"platform"`
		} `json:"manifests"`
	}
	if json.Unmarshal(raw, &index) == nil && len(index.Manifests) > 0 {
		// Pick the first real platform manifest (skip attestations).
		for _, m := range index.Manifests {
			if m.Platform.OS != "" && m.Platform.OS != "unknown" {
				return s.fetchConfigDigest(ctx, token, m.Digest)
			}
		}
		// Fallback: use the very first entry.
		return s.fetchConfigDigest(ctx, token, index.Manifests[0].Digest)
	}

	// Single manifest — extract config digest directly.
	var manifest struct {
		Config struct {
			Digest string `json:"digest"`
		} `json:"config"`
	}
	if err := json.Unmarshal(raw, &manifest); err != nil {
		return "", err
	}
	if manifest.Config.Digest == "" {
		return "", fmt.Errorf("empty config digest")
	}
	return manifest.Config.Digest, nil
}

