package ingestion

import (
	"context"
	"fmt"
	"net/http"
	"net/http/httptest"
	"testing"
	"time"
)

func TestECRPublicSourceName(t *testing.T) {
	src := NewECRPublicSource(http.DefaultClient, "i6b2w2n6/op-node", "")
	if got := src.Name(); got != "ecr-public" {
		t.Errorf("Name() = %q, want %q", got, "ecr-public")
	}
}

func newECRPublicTestServer(configCreated string) *httptest.Server {
	return httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/json")
		switch r.URL.Path {
		case "/token/":
			w.Write([]byte(`{"token": "test-token"}`))
		case "/v2/i6b2w2n6/op-node/tags/list":
			if r.Header.Get("Authorization") != "Bearer test-token" {
				w.WriteHeader(http.StatusUnauthorized)
				return
			}
			w.Write([]byte(`{"name": "i6b2w2n6/op-node", "tags": ["v1.0.0", "v1.1.0"]}`))
		case "/v2/i6b2w2n6/op-node/manifests/v1.0.0":
			w.Write([]byte(`{"config":{"digest":"sha256:aaa"}}`))
		case "/v2/i6b2w2n6/op-node/manifests/v1.1.0":
			w.Write([]byte(`{"config":{"digest":"sha256:bbb"}}`))
		case "/v2/i6b2w2n6/op-node/blobs/sha256:aaa":
			w.Write([]byte(fmt.Sprintf(`{"created":"%s"}`, configCreated)))
		case "/v2/i6b2w2n6/op-node/blobs/sha256:bbb":
			w.Write([]byte(`{"created":"2025-11-20T08:30:00Z"}`))
		default:
			w.WriteHeader(http.StatusNotFound)
		}
	}))
}

func TestECRPublicFetchNewReleases(t *testing.T) {
	srv := newECRPublicTestServer("2025-10-10T14:38:14Z")
	defer srv.Close()

	src := NewECRPublicSource(srv.Client(), "i6b2w2n6/op-node", "src-123")
	src.baseURL = srv.URL

	results, err := src.FetchNewReleases(context.Background())
	if err != nil {
		t.Fatalf("FetchNewReleases: %v", err)
	}

	if len(results) != 2 {
		t.Fatalf("got %d results, want 2", len(results))
	}
	if results[0].RawVersion != "v1.0.0" {
		t.Errorf("results[0].RawVersion = %q, want %q", results[0].RawVersion, "v1.0.0")
	}
	if results[0].Repository != "i6b2w2n6/op-node" {
		t.Errorf("results[0].Repository = %q, want %q", results[0].Repository, "i6b2w2n6/op-node")
	}

	// Verify timestamp comes from the config blob, not time.Now()
	expected, _ := time.Parse(time.RFC3339, "2025-10-10T14:38:14Z")
	if !results[0].Timestamp.Equal(expected) {
		t.Errorf("results[0].Timestamp = %v, want %v", results[0].Timestamp, expected)
	}
	expected2, _ := time.Parse(time.RFC3339, "2025-11-20T08:30:00Z")
	if !results[1].Timestamp.Equal(expected2) {
		t.Errorf("results[1].Timestamp = %v, want %v", results[1].Timestamp, expected2)
	}
}

func TestECRPublicFetchEmpty(t *testing.T) {
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/json")
		switch r.URL.Path {
		case "/token/":
			w.Write([]byte(`{"token": "test-token"}`))
		default:
			w.Write([]byte(`{"name": "i6b2w2n6/op-node", "tags": []}`))
		}
	}))
	defer srv.Close()

	src := NewECRPublicSource(srv.Client(), "i6b2w2n6/op-node", "")
	src.baseURL = srv.URL

	results, err := src.FetchNewReleases(context.Background())
	if err != nil {
		t.Fatalf("FetchNewReleases: %v", err)
	}
	if len(results) != 0 {
		t.Fatalf("got %d results, want 0", len(results))
	}
}

func TestECRPublicTimestampFallback(t *testing.T) {
	// Manifest endpoint fails — should fall back to time.Now() gracefully
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/json")
		switch r.URL.Path {
		case "/token/":
			w.Write([]byte(`{"token": "test-token"}`))
		case "/v2/i6b2w2n6/op-node/tags/list":
			w.Write([]byte(`{"name": "i6b2w2n6/op-node", "tags": ["v1.0.0"]}`))
		default:
			w.WriteHeader(http.StatusInternalServerError)
		}
	}))
	defer srv.Close()

	src := NewECRPublicSource(srv.Client(), "i6b2w2n6/op-node", "")
	src.baseURL = srv.URL

	before := time.Now()
	results, err := src.FetchNewReleases(context.Background())
	if err != nil {
		t.Fatalf("FetchNewReleases: %v", err)
	}
	if len(results) != 1 {
		t.Fatalf("got %d results, want 1", len(results))
	}
	// Fallback should use approximately time.Now()
	if results[0].Timestamp.Before(before) {
		t.Errorf("fallback timestamp %v is before test start %v", results[0].Timestamp, before)
	}
}

func TestECRPublicTokenFailure(t *testing.T) {
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.WriteHeader(http.StatusInternalServerError)
	}))
	defer srv.Close()

