func TestECRPublicManifestList(t *testing.T) {
	// Simulates a multi-arch image (manifest list / OCI index) where the tag
	// resolves to an index containing platform-specific sub-manifests.
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/json")
		switch r.URL.Path {
		case "/token/":
			w.Write([]byte(`{"token": "test-token"}`))
		case "/v2/i6b2w2n6/op-node/tags/list":
			w.Write([]byte(`{"name": "i6b2w2n6/op-node", "tags": ["v2.0.0"]}`))
		case "/v2/i6b2w2n6/op-node/manifests/v2.0.0":
			// Return a manifest list (OCI index)
			w.Write([]byte(`{
				"manifests": [
					{"digest": "sha256:sub-amd64", "platform": {"architecture": "amd64", "os": "linux"}},
					{"digest": "sha256:sub-attest", "platform": {"architecture": "unknown", "os": "unknown"}}
				]
			}`))
		case "/v2/i6b2w2n6/op-node/manifests/sha256:sub-amd64":
			// Sub-manifest with config digest
			w.Write([]byte(`{"config":{"digest":"sha256:cfg-amd64"}}`))
		case "/v2/i6b2w2n6/op-node/blobs/sha256:cfg-amd64":
			w.Write([]byte(`{"created":"2025-11-17T19:42:43Z"}`))
		default:
			w.WriteHeader(http.StatusNotFound)
		}
	}))
	defer srv.Close()

	src := NewECRPublicSource(srv.Client(), "i6b2w2n6/op-node", "")
	src.baseURL = srv.URL

	results, err := src.FetchNewReleases(context.Background())
	if err != nil {
		t.Fatalf("FetchNewReleases: %v", err)
	}
	if len(results) != 1 {
		t.Fatalf("got %d results, want 1", len(results))
	}

	expected, _ := time.Parse(time.RFC3339, "2025-11-17T19:42:43Z")
	if !results[0].Timestamp.Equal(expected) {
		t.Errorf("Timestamp = %v, want %v (should resolve through manifest list)", results[0].Timestamp, expected)
	}
}
